from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
from functools import wraps
import time
import secrets
import os
from werkzeug.security import check_password_hash, generate_password_hash

app = Flask(__name__)

# Security configuration
METRICS_TOKEN = os.environ.get('METRICS_TOKEN', secrets.token_urlsafe(32))
METRICS_USERNAME = os.environ.get('METRICS_USERNAME', 'prometheus')
METRICS_PASSWORD_HASH = generate_password_hash(os.environ.get('METRICS_PASSWORD', secrets.token_urlsafe(16)))

# Prometheus metrics
request_count = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_latency = Histogram(
    'http_request_duration_seconds',
    'HTTP request latency',
    ['method', 'endpoint']
)

active_requests = Gauge(
    'http_requests_in_progress',
    'Number of HTTP requests in progress',
    ['method', 'endpoint']
)

business_transactions = Counter(
    'business_transactions_total',
    'Total business transactions',
    ['transaction_type', 'status']
)

business_revenue = Counter(
    'business_revenue_total',
    'Total business revenue',
    ['currency']
)

active_users = Gauge(
    'active_users',
    'Number of active users'
)

database_connections = Gauge(
    'database_connections',
    'Number of active database connections'
)

cache_hit_rate = Gauge(
    'cache_hit_rate',
    'Cache hit rate percentage'
)

error_count = Counter(
    'application_errors_total',
    'Total application errors',
    ['error_type']
)

# Security decorators
def require_metrics_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth = request.authorization
        token = request.headers.get('X-Metrics-Token')
        
        # Token-based authentication
        if token and secrets.compare_digest(token, METRICS_TOKEN):
            return f(*args, **kwargs)
        
        # Basic authentication
        if auth and auth.username == METRICS_USERNAME and check_password_hash(METRICS_PASSWORD_HASH, auth.password):
            return f(*args, **kwargs)
        
        return jsonify({'error': 'Unauthorized'}), 401
    
    return decorated_function

def instrument_request(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        method = request.method
        endpoint = request.endpoint or 'unknown'
        
        active_requests.labels(method=method, endpoint=endpoint).inc()
        
        start_time = time.time()
        
        try:
            response = f(*args, **kwargs)
            status = response[1] if isinstance(response, tuple) else 200
            
            request_count.labels(method=method, endpoint=endpoint, status=status).inc()
            
            return response
        except Exception as e:
            error_count.labels(error_type=type(e).__name__).inc()
            request_count.labels(method=method, endpoint=endpoint, status=500).inc()
            raise
        finally:
            duration = time.time() - start_time
            request_latency.labels(method=method, endpoint=endpoint).observe(duration)
            active_requests.labels(method=method, endpoint=endpoint).dec()
    
    return decorated_function

# Metrics endpoint with security
@app.route('/metrics')
@require_metrics_auth
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

# Application endpoints
@app.route('/')
@instrument_request
def index():
    return jsonify({'message': 'Welcome to the monitored application'}), 200

@app.route('/health')
@instrument_request
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/api/users', methods=['GET'])
@instrument_request
def get_users():
    active_users.set(42)
    return jsonify({'users': [{'id': 1, 'name': 'User 1'}, {'id': 2, 'name': 'User 2'}]}), 200

@app.route('/api/transaction', methods=['POST'])
@instrument_request
def create_transaction():
    data = request.get_json() or {}
    transaction_type = data.get('type', 'purchase')
    amount = data.get('amount', 0)
    currency = data.get('currency', 'USD')
    
    try:
        business_transactions.labels(transaction_type=transaction_type, status='success').inc()
        business_revenue.labels(currency=currency).inc(amount)
        
        return jsonify({
            'transaction_id': secrets.token_hex(8),
            'status': 'completed',
            'amount': amount,
            'currency': currency
        }), 201
    except Exception as e:
        business_transactions.labels(transaction_type=transaction_type, status='failed').inc()
        error_count.labels(error_type='transaction_error').inc()
        return jsonify({'error': 'Transaction failed'}), 500

@app.route('/api/cache/stats', methods=['GET'])
@instrument_request
def cache_stats():
    cache_hit_rate.set(85.5)
    return jsonify({'hit_rate': 85.5, 'total_requests': 1000}), 200

@app.route('/api/database/stats', methods=['GET'])
@instrument_request
def database_stats():
    database_connections.set(15)
    return jsonify({'active_connections': 15, 'max_connections': 100}), 200

@app.route('/api/simulate/error', methods=['GET'])
@instrument_request
def simulate_error():
    error_type = request.args.get('type', 'generic')
    error_count.labels(error_type=error_type).inc()
    return jsonify({'error': 'Simulated error'}), 500

@app.errorhandler(404)
def not_found(error):
    request_count.labels(method=request.method, endpoint='not_found', status=404).inc()
    return jsonify({'error': 'Not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    error_count.labels(error_type='internal_server_error').inc()
    return jsonify({'error': 'Internal server error'}), 500

